import jwt from "jsonwebtoken";
var createToken = (payload, secret, expiresIn) => {
  const token = jwt.sign(payload, secret, { expiresIn });
  return token;
};
var verifyToken = (token, secret) => {
  try {
    const verifiedToken = jwt.verify(token, secret);
    return {
      success: true,
      data: verifiedToken
    };
  } catch (error) {
    console.log(error, "error in refresh token");
    return {
      success: false,
      error: error?.message
    };
  }
};
var jwtUtils = {
  createToken,
  verifyToken
};

// src/modules/auth/auth.service.ts
var createUserInDb = async (payload) => {
  const { firstName, lastName, email, password, status, role } = payload;
  const user = await prisma.user.findUnique({
    where: { email }
  });
  if (user)
    throw {
      statusCode: httpStatus.CONFLICT,
      message: "User Already Exist , Please Login"
    };
  const hashPassword = await bcrypt.hash(
    password,
    Number(config_default.bcrypt_salt_round)
  );
  const result = await prisma.user.create({
    data: {
      firstName,
      lastName,
      email,
      password: hashPassword,
      status,
      role
    },
    omit: {
      password: true
    }
  });
  return result;
};
var loginUserInDb = async (email, password) => {
  const user = await prisma.user.findUnique({
    where: { email }
  });
  if (!user)
    throw {
      statusCode: httpStatus.NOT_FOUND,
      message: "User Not Found, Register First"
    };
  const isValidPassword = await bcrypt.compare(password, user.password);
  if (!isValidPassword)
    throw {
      statusCode: httpStatus.UNAUTHORIZED,
      message: "Invalid Password Try Again"
    };
  const jwtPayload = {
    userId: user.id,
    firstName: user.firstName,
    lastName: user.lastName,
    email: user.email,
    role: user.role,
    status: user.status
  };
  const accessToken = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_access_secret,
    config_default.jwt_access_expires_in
  );
  const refreshToken2 = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_refresh_access_secret,
    config_default.jwt_refresh_expires_in
  );
  return { accessToken, refreshToken: refreshToken2 };
};
var getCurrentUserFromDb = async (id) => {
  const currentUser = await prisma.user.findUniqueOrThrow({
    where: { id },
    omit: { password: true }
  });
  return currentUser;
};
var refreshToken = async (token) => {
  const verifiedToken = jwtUtils.verifyToken(
    token,
    config_default.jwt_refresh_access_secret
  );
  if (!verifiedToken.success) throw new Error(verifiedToken?.error);
  const { name, id, email, role } = verifiedToken.data;
  const user = await prisma.user.findUniqueOrThrow({
    where: {
      id,
      email
    }
  });
  if (!user) throw new Error("User is not exist please register first");
  if (user.status === UserStatus.BAN) throw new Error("User is banned ");
  const jwtPayload = {
    name,
    id,
    email,
    role
  };
  const accessToken = jwtUtils.createToken(
    jwtPayload,
    config_default.jwt_access_secret,
    config_default.jwt_access_expires_in
  );
  return accessToken;
};
