var getAllPropertiesFromDb = async (query) => {
  let andConditions = [];
  if (query.searchTerm) {
    andConditions.push({
      OR: [
        //search by location
        {
          location: {
            contains: query.searchTerm,
            mode: "insensitive"
          }
        },
        //search by amenities
        {
          amenities: {
            contains: query.searchTerm,
            mode: "insensitive"
          }
        },
        //search by property type(category)
        {
          category: {
            name: {
              contains: query.searchTerm,
              mode: "insensitive"
            }
          }
        }
        //serach by price range will check later
      ]
    });
  }
  if (query.location) {
    andConditions.push({
      location: {
        contains: query.location,
        mode: "insensitive"
      }
    });
  }
  if (query.type) {
    andConditions.push({
      category: {
        name: {
          equals: query.type,
          mode: "insensitive"
        }
      }
    });
  }
  if (query.minPrice || query.maxPrice) {
    const priceCondition = {};
    if (query.minPrice) {
      priceCondition.gte = Number(query.minPrice);
    }
    if (query.maxPrice) {
      priceCondition.lte = Number(query.maxPrice);
    }
    andConditions.push({ price: priceCondition });
  }
  const propertiesResult = await prisma.properties.findMany({
    where: {
      AND: andConditions
    },
    include: {
      category: true,
      user: {
        omit: {
          password: true
        }
      }
    }
  });
  return propertiesResult;
};
